import aiohttp, discord

class LLMPromptModal(discord.ui.Modal, title="LLM Prompt"):
    prompt = discord.ui.TextInput(label="Prompt", style=discord.TextStyle.paragraph, placeholder="Enter your prompt here...", required=True)

    async def on_submit(self, interaction: discord.Interaction):
        await interaction.response.defer()
        try:
            async with aiohttp.ClientSession() as session:
                async with session.post('http://localhost:11434/api/generate', json={'model': 'smollm2:135m', 'prompt': self.prompt.value, 'stream': False}) as resp:
                    if resp.status == 200:
                        data = await resp.json()
                        await interaction.followup.send(data.get('response', 'Empty'), ephemeral=True)
                    else:
                        await interaction.followup.send('Ollama Error', ephemeral=True)
        except (aiohttp.ClientConnectorError, ConnectionRefusedError):
            await interaction.followup.send('❌ Ollama is not available. Please ensure Ollama is running on localhost:11434.', ephemeral=True)
        except Exception as e:
            await interaction.followup.send(f'Error: {e}', ephemeral=True)

await interaction.response.send_modal(LLMPromptModal())

