import json
import os

# Check if user has interacted before by checking a simple file-based tracking system
users_file = "users.json"
user_id = str(interaction.user.id)

if os.path.exists(users_file):
    with open(users_file, "r") as f:
        users = json.load(f)
else:
    users = {}

if user_id not in users:
    users[user_id] = {"first_interaction": True}
    with open(users_file, "w") as f:
        json.dump(users, f)
    
    await interaction.response.send_message(
        "Welcome! This is your first command. To access logs, visit: http://YOUR_SERVER_IP:5000\n"
        "If you need to appeal a ban, please follow the instructions on the appeals page."
    )
else:
    await interaction.response.defer()
